import { defineComponent, computed } from 'vue';
import { ButtonInterface, } from '@baklavajs/renderer-vue'; // eslint-disable-line object-curly-newline
import { getOptionName } from '../../../custom/CustomNode.js';
import { menuState } from '../../../core/nodeCreation/ConfigurationState.ts';
import { createGroupFromSelection } from '../../../core/nodeCreation/Configuration.ts';
import newInputInterface from './utils.ts';
function randomColor() {
    // eslint-disable-next-line no-bitwise
    return `#${((1 << 24) * Math.random() | 0).toString(16).padStart(6, '0')}`;
}
export default defineComponent({
    setup() {
        const newGroup = {
            name: 'New Group',
            color: randomColor(),
        };
        const close = () => {
            menuState.groupMenu = false;
        };
        const groupName = newInputInterface('Group name', newGroup.name, 'name');
        const groupColor = newInputInterface('Group color', newGroup.color, 'color');
        const addGroupMenu = computed(() => {
            const button = new ButtonInterface('Create group', () => {
                const prop = {
                    name: newGroup.name,
                    color: newGroup.color,
                };
                createGroupFromSelection(prop.name, prop.color);
                close();
            });
            button.componentName = 'ButtonInterface';
            return button;
        });
        const configurationOptions = computed(() => [groupName.value, groupColor.value, addGroupMenu.value]);
        return {
            configurationOptions,
            getOptionName,
            newGroup,
        };
    },
});
